import React from 'react';
import './Portfolio.css'
import placeholderImg from '../images/Image1.png';

const Projects = () => {
  const randomWordsGrid = "Innovation Code Interface Creative Scalable Future Dynamic System Logic Pixel Vector Development Minimalist Abstract Clean Modern Professional Velocity Synergy Craft Digital Studio Vision Canvas Strategy architecture robust functionality";

  return (
    <section id="portfolio" className="portfolio-section">
      <div className="mountains-hero">
        <div className="section-header-box">PROJECTS</div>
      </div>

      <div className="portfolio-filter-bar">
        <span className="active">All</span>
        <span>Coded</span>
        <span>Designed</span>
      </div>

      {/* <div className="portfolio-grid">
        {[0, 1, 2, 3, 4, 5].map((index) => {

          if (index === 1 || index === 3) {
            return (
              <div key={index} className="portfolio-item word-cloud-tile">
                <div className="word-cloud-content">
                  {randomWordsGrid}
                </div>
              </div>
            );
          }

          return (
            <div key={index} className="portfolio-item circle-tile">
              <div className="circle-container">
                <img src={placeholderImg} alt="Project" className="portfolio-img-fill" />
                <div className="portfolio-overlay">
                  <h5>eatsome.</h5>
                  <div className="overlay-links">| DEMO | MORE |</div>
                </div>
              </div>
            </div>
          );
        })}
      </div> */}

      <div className="portfolio-grid">
        <div className='pic1'><img src="placeholderImg" alt="" /></div>
        <div className='pic2'></div>
        <div className='pic3'></div>
        <div className='pic4'></div>
        <div className='pic5'></div>
        <div className='pic6'></div>

        </div>

      <div className="grid-footer">And many more to come!</div>
    </section>
  );
};

export default Projects;
